H3_model_gam <- 
  bam(H3_form_gam, 
      data = GAM_data, 
      discrete = TRUE,
      method = "fREML",
      nthreads = 10
      )

r1 <- start_value_rho(H3_model_gam, 
                      plot=TRUE)
```

