### Analysis


::: {.cell filename='Fit the model for H4'}

```{.r .cell-code .hidden}
#| filename: Fit the model for H4
#| fig-height: 10
#| fig-width: 8
H4_formula_1 <- geo.MEDI ~ site*activity + (1|Id)
H4_formula_0 <- geo.MEDI ~ site + (1|Id)
H4_formula_1_ni <- geo.MEDI ~ site + activity + (1|Id)
H4_formula_1_ns <- geo.MEDI ~ activity + (1|Id)

#confirmatory
H4_model_1 <- 
  glmmTMB(H4_formula_1, 
          data = activity_data, 
          REML = FALSE, 
          family = tweedie(),
          contrasts = list(site = "contr.sum")
          )
H4_model_0 <- 
  glmmTMB(H4_formula_0, 
          data = activity_data, 
          REML = FALSE, 
          family = tweedie(),
          contrasts = list(site = "contr.sum")
          )
#exploratory:
H4_model_1_ni <- 
  glmmTMB(H4_formula_1_ni, 
          data = activity_data, 
          REML = FALSE, 
          family = tweedie(),
          contrasts = list(site = "contr.sum")
          )
H4_model_1_ns <- 
  glmmTMB(H4_formula_1_ns, 
          data = activity_data, 
          REML = FALSE, 
          family = tweedie(),
          )

comp_confirmatory <- 
anova(H4_model_0, H4_model_1)
comp_confirmatory
```

