### Analysis


::: {.cell}

```{.r .cell-code .hidden}
H7_models <- 
H7_data |> 
  mutate(
    across(c(H7_1, H7_0),
           \(x) pmap(list(data, x),
                     \(data, formula) {
                       bam(formula, 
                            data = data, 
                            discrete = TRUE,
                            method = "fREML",
                            nthreads = 10
                            )
                     })),
    AICs = pmap(list(H7_1, H7_0), AIC),
    dAIC = map_dbl(AICs, \(x) x$AIC[[1]] - x$AIC[[2]]),
    signif = dAIC < -2
  )
```
:::


